module top_module(clk, en, we, addr, di, dout);input clk;
input we;
input en;
input [8:0] addr;
input [7:0] di;
output [7:0] dout;

reg [7:0] RAM [511:0];
reg [7:0] dout;

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt)
begin
  if (en)
    begin
      if (we)
        RAM[addr]<=di;
      dout <= RAM[addr];
    end
end

endmodule
